import { useState, useMemo } from 'react';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import useForm from '../../hooks/useForm';
import { FormInput, FormSelect, FormTextarea, FormToggle } from '../../components/common/FormFields';

const FormLayouts = () => {
    // 1. Main Form Schema and Hook (Forms 1 & 2)
    const mainSchema = useMemo(() => ({
        fn: { required: true, label: 'First Name' },
        mn: { label: 'Middle Name' },
        sn: { required: true, label: 'Last Name' },
        gender: { required: true, label: 'Gender' },
        email: { required: true, type: 'email', label: 'Email Address' },
        phone: { required: true, label: 'Phone Number' }
    }), []);

    const mainInitialValues = useMemo(() => ({
        fn: '', mn: '', sn: '', gender: '', dob: '', phone: '', email: '', address: ''
    }), []);

    const mainForm = useForm(mainInitialValues, mainSchema);
    const { values: mainValues, errors: mainErrors, handleChange: handleMainChange, handleSubmit: handleMainSubmit, resetForm: resetMainForm, setValues: setMainValues } = mainForm;

    const [photoPreview, setPhotoPreview] = useState(null);
    const handlePhotoChange = (e) => { const file = e.target.files[0]; if (file) { setPhotoPreview(URL.createObjectURL(file)); } };

    const onMainSubmit = (data) => {
        console.log('Main Form Submitted:', data);
        alert('Form Submitted Successfully!');
    };

    const handleMainReset = () => {
        resetMainForm();
        setPhotoPreview(null);
    };

    // 2. Checkbox Base Schema and Hook (Form 4)
    const checkInitialValues = useMemo(() => ({
        chk01: false, chk02: false, chk03: false
    }), []);

    const checkboxForm = useForm(checkInitialValues, {});
    const { values: checkValues, handleChange: handleCheckChange, handleSubmit: handleCheckSubmit, resetForm: resetCheckForm } = checkboxForm;

    const onCheckSubmit = (data) => {
        const checkedIds = Object.keys(data).filter(id => data[id]);
        console.log('Checked checkbox IDs:', checkedIds);
    };

    // 3. Radio Base Schema and Hook (Form 5)
    const radioInitialValues = useMemo(() => ({
        radx: ''
    }), []);

    const radioForm = useForm(radioInitialValues, {});
    const { values: radioValues, handleChange: handleRadioChange, handleSubmit: handleRadioSubmit, resetForm: resetRadioForm } = radioForm;

    const onRadioSubmit = (data) => {
        console.log('Selected Radio Button:', data.radx);
    };

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'> <span><h2>Form Layouts</h2><p>Input, Checkbox, Radio</p></span>  </div>
            </header>
            <div className='admin-pager-body'>
                <div className='flex-case gap'>
                    <div className='w5'>
                        <form className='pagelet' noValidate onSubmit={handleMainSubmit(onMainSubmit)}>
                            <div className='pagelet-head'>
                                <h3><Icon icon={icons.signature} />H3 Header</h3>
                                <div className='pagelet-head-btn'>
                                    <button type='button' className='button icon btn-link'><Icon icon={icons.ellipsisV} /></button>
                                </div>
                            </div>
                            <div className='pagelet-body'>
                                <div className='form-case'>
                                    <div className='form-row form-profile'>
                                        <div className='form-profile-photo'>
                                            <img src={photoPreview || '/defaults/avatar.png'} alt='Profile Preview' loading='lazy' /><label htmlFor='photo-upload'>Select Photo</label>
                                            <input id='photo-upload' type='file' accept='image/*' onChange={handlePhotoChange} style={{ display: 'none' }} />
                                        </div>
                                        <div className='form-profile-info'>
                                            <div className='form-row'>
                                                <FormInput label="First Name" name="fn" placeholder="First Name" value={mainValues.fn} error={mainErrors.fn} onChange={handleMainChange} required className="w5-fx" />
                                                <FormInput label="Middle Name" name="mn" placeholder="Middle Name" value={mainValues.mn} onChange={handleMainChange} className="w5-fx" />
                                            </div>
                                            <FormInput label="Last Name" name="sn" placeholder="Last Name" value={mainValues.sn} error={mainErrors.sn} onChange={handleMainChange} required />
                                        </div>
                                    </div>
                                    <div className='form-dvr'></div>
                                    <div className='form-row'>
                                        <div className='w5'>
                                            <div className='form-row-fx'>
                                                <FormSelect label="Gender" name="gender" value={mainValues.gender} error={mainErrors.gender} onChange={handleMainChange} required className="w4-fx" options={[{ value: '1', label: 'Male' }, { value: '2', label: 'Female' }]} />
                                                <FormInput label="Birthday" name="dob" type="date" value={mainValues.dob} onChange={handleMainChange} className="w6-fx" />
                                            </div>
                                        </div>
                                        <div className='w5'>
                                            <div className='input-case'><p>Switches</p>
                                                <div className='form-row-fx'>
                                                    <div className='toggle-switch'> <label><input type='checkbox' /><span></span></label> </div>
                                                    <div className='toggle-switch radius'> <label><input type='checkbox' /><span></span></label> </div>
                                                    <div className='toggle-switch square'> <label><input type='checkbox' /><span></span></label> </div>
                                                    <div className='toggle-switch on-off'> <label><input type='checkbox' /><span></span></label> </div>
                                                    <div className='toggle-switch small'> <label><input type='checkbox' /><span></span></label> </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    <div className='form-row'>
                                        <FormInput label="Phone Number" name="phone" placeholder="Phone Number" value={mainValues.phone} error={mainErrors.phone} onChange={handleMainChange} required className="w5" />
                                        <FormInput label="Email" name="email" type="email" placeholder="Email" value={mainValues.email} error={mainErrors.email} onChange={handleMainChange} required className="w5" />
                                    </div>
                                    <FormTextarea label="Address" name="address" placeholder="Address" rows={2} value={mainValues.address} onChange={handleMainChange} />
                                </div>
                            </div>
                            <div className='pagelet-foot'>
                                <button type='button' className='button btn-secondary' onClick={handleMainReset}><Icon icon={icons.times} />Reset</button>
                                <button type='submit' className='button'><Icon icon={icons.send} />Submit</button>
                            </div>
                        </form>
                    </div>
                    <div className='w5-fx'>
                        <form className='pagelet' noValidate onSubmit={handleMainSubmit(onMainSubmit)}>
                            <div className='pagelet-head'>
                                <h4><Icon icon={icons.signature} />Header h4</h4>
                                <div className='pagelet-head-btn'>
                                    <button type='button' className='button icon btn-link'><Icon icon={icons.ellipsisV} /></button>
                                </div>
                            </div>
                            <div className='pagelet-body'>
                                <div className='form-case'>
                                    <div className='form-row'>
                                        <FormInput label="Left Icon" name="fn" placeholder="First Name" value={mainValues.fn} error={mainErrors.fn} onChange={handleMainChange} required iconLeft={icons.user} className="w5-fx" />
                                        <FormInput label="Right Icon" name="mn" placeholder="Middle Name" value={mainValues.mn} onChange={handleMainChange} iconRight={icons.user} className="w5-fx" />
                                    </div>
                                    <div className='form-row'>
                                        <div className='w5-fx'>
                                            <div className='input-case'>
                                                <p>Left Select Icon</p>
                                                <div className='input-group left'>
                                                    <select name='gender' required onChange={handleMainChange} value={mainValues.gender}><option value=''>Select</option><option value='1'>Male</option><option value='2'>Female</option></select>
                                                    <Icon icon={icons.userPlus} className='input-icon' />
                                                </div>
                                            </div>
                                        </div>
                                        <FormInput label="Right Icon" name="phone" placeholder="Phone Number" value={mainValues.phone} error={mainErrors.phone} onChange={handleMainChange} required iconRight={icons.phone} className="w5-fx" />
                                    </div>
                                    <div className='form-dvr'></div>
                                    <FormInput label="Left & Right Icon" name="email" placeholder="Email" value={mainValues.email} error={mainErrors.email} onChange={handleMainChange} required iconLeft={icons.email} iconRight={icons.check} />
                                    <FormInput label="Address" name="address" placeholder="Address with rows=1" value={mainValues.address} onChange={handleMainChange} iconLeft={icons.home} />
                                    <FormTextarea label="Address" name="address" placeholder="Address with rows=2" rows={2} value={mainValues.address} onChange={handleMainChange} />
                                </div>
                            </div>
                            <div className='pagelet-foot'>
                                <button type='submit' className='button'><Icon icon={icons.send} />Submit</button>
                            </div>
                        </form>
                    </div>
                </div>

                <div className='flex-case gap'>
                    <div className='w5'>
                        <div className='pagelet'><div className='pagelet-in'>
                            <div className='form-case'>
                                <h3>CHECKBOX STYLE</h3>
                                <ul className='radio-case'>
                                    <li><label><input type='checkbox' id='chkx1' />Checkbox inside label</label></li>
                                    <li><input type='checkbox' id='chkx2' /><label htmlFor='chkx2'>Checkbox using htmlFor</label></li>
                                    <li><input type='checkbox' id='chkx3' /><p>Checkbox with p tag</p></li>
                                    <li><input type='checkbox' id='chkx4' disabled /><p>Checkbox Disabled</p></li>
                                    <li><label><input type='radio' id='radx1' />Radio inside label</label></li>
                                </ul>
                            </div>
                        </div></div>
                    </div>
                    <div className='w5'>
                        <form className='pagelet' onSubmit={handleCheckSubmit(onCheckSubmit)}>
                            <div className='pagelet-head'>
                                <h4><Icon icon={icons.successCircle} />CHECKBOX BASE</h4>
                            </div>
                            <div className='pagelet-in'>
                                <div className='form-case'>
                                    <ul className='radio-case'>
                                        <li><label><input type='checkbox' name='chk01' checked={checkValues.chk01} onChange={handleCheckChange} />Check this custom checkbox 1</label></li>
                                        <li><label><input type='checkbox' name='chk02' checked={checkValues.chk02} onChange={handleCheckChange} />Check this custom checkbox 2</label></li>
                                        <li><label><input type='checkbox' name='chk03' checked={checkValues.chk03} onChange={handleCheckChange} />Check this custom checkbox 3</label></li>
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-foot'>
                                <button type='button' className='button btn-secondary' onClick={resetCheckForm}><Icon icon={icons.times} />Reset</button>
                                <button type='submit' className='button'><Icon icon={icons.send} />Submit</button>
                            </div>
                        </form>
                    </div>
                    <div className='w5'>
                        <form className='pagelet' onSubmit={handleRadioSubmit(onRadioSubmit)}>
                            <div className='pagelet-head'>
                                <h4><Icon icon={icons.successCircle} />RADIO BASE</h4>
                            </div>
                            <div className='pagelet-in'>
                                <div className='form-case'>
                                    <ul className='radio-case'>
                                        <li><label><input type='radio' name='radx' value='option 1' checked={radioValues.radx === 'option 1'} onChange={handleRadioChange} />Check this custom checkbox 1</label></li>
                                        <li><label><input type='radio' name='radx' value='option 2' checked={radioValues.radx === 'option 2'} onChange={handleRadioChange} />Check this custom checkbox 1</label></li>
                                        <li><label><input type='radio' name='radx' value='option 3' checked={radioValues.radx === 'option 3'} onChange={handleRadioChange} />Check this custom checkbox 1</label></li>
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-foot'>
                                <button type='button' className='button btn-secondary' onClick={resetRadioForm}><Icon icon={icons.times} />Reset</button>
                                <button type='submit' className='button'><Icon icon={icons.send} />Submit</button>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        </div>);

};
export default FormLayouts;
